import { FormsModule } from '@angular/forms';
import { DatePipe, CurrencyPipe } from '@angular/common';
import './homologation.css';
import './icons.css';

const api = (location.hostname === 'localhost' ? 'http://localhost:8080' : (window as any).__API_URL__ || '') + '/api';
const authInterceptor = (req: any, next: any) => next(req.clone({setHeaders: {Authorization: `Bearer ${localStorage.getItem('ello_token') || ''}`}}));

@Component({selector:'app-root',standalone:true,imports:[FormsModule,DatePipe,CurrencyPipe],template:`
<div class="homologation-banner">AMBIENTE DE HOMOLOGAÇÃO — NÃO INSIRA DADOS REAIS DE PACIENTES</div>
@if (isLanding) {
  <div class="landing"><nav class="landing-nav"><a class="landing-logo" href="/"><b>e</b><span>ello<small>clinic</small></span></a><div><a href="#recursos">Recursos</a><a href="#precos">Planos</a><a href="#seguranca">Segurança</a></div><button (click)="openLogin()">Entrar</button></nav>
  <main><section class="hero"><div class="hero-copy"><span class="eyebrow">GESTÃO PARA CLÍNICAS MULTIDISCIPLINARES</span><h1>Mais tempo para cuidar.<br><em>Mais clareza para crescer.</em></h1><p>Agenda, prontuários, financeiro e gestão profissional conectados em uma plataforma segura e simples de usar.</p><div class="hero-actions"><button class="landing-primary" (click)="startTrial('professional')">Começar teste gratuito <span>→</span></button><a href="#recursos">Conhecer a plataforma</a></div><small>✓ 14 dias grátis · ✓ Sem cartão · ✓ Cancele quando quiser</small></div><div class="hero-visual"><div class="mock-window"><header><i></i><i></i><i></i><span>ello clinic</span></header><div class="mock-app"><aside><b>e</b><i></i><i></i><i></i><i></i><i></i></aside><section><small>VISÃO GERAL</small><h3>Bom dia, Ana!</h3><div class="mock-metrics"><i></i><i></i><i></i></div><div class="mock-content"><div><b>Agenda de hoje</b><span></span><span></span><span></span></div><div><b>Operação</b><em>87%</em></div></div></section></div></div><div class="floating-card patients">♙ <span><b>+18 pacientes</b><small>este mês</small></span></div><div class="floating-card secure">✓ <span><b>Dados protegidos</b><small>LGPD e auditoria</small></span></div></div></section>
  <section class="trust"><span>Uma plataforma para toda a clínica</span><div><b>Psicologia</b><b>Fonoaudiologia</b><b>Terapia Ocupacional</b><b>Psicopedagogia</b><b>Neuropsicologia</b></div></section>
  <section id="recursos" class="features"><div class="section-title"><span>DO PRIMEIRO CONTATO AO RESULTADO</span><h2>Tudo conectado. Nada se perde.</h2><p>Uma visão completa da operação sem tirar a autonomia de cada profissional.</p></div><div class="feature-grid"><article><i>▦</i><h3>Agenda inteligente</h3><p>Visão geral e individual, recorrências e prevenção automática de conflitos.</p><small>Confirmação por link →</small></article><article><i>▤</i><h3>Prontuário seguro</h3><p>Evoluções, linha do tempo e planos terapêuticos com acesso controlado.</p><small>Histórico completo →</small></article><article><i>◇</i><h3>Financeiro claro</h3><p>Receitas, despesas, inadimplência e resultado sempre atualizados.</p><small>Fluxo de caixa →</small></article><article><i>◈</i><h3>Repasses automáticos</h3><p>Calcule valores por profissional, serviço e regra de pagamento.</p><small>Fechamento simples →</small></article><article><i>▥</i><h3>Relatórios que orientam</h3><p>Ocupação, receita e produtividade para decisões baseadas em dados.</p><small>Indicadores reais →</small></article><article><i>♧</i><h3>Multiunidade e equipe</h3><p>Perfis, permissões, salas e unidades em um único ambiente.</p><small>Pronto para crescer →</small></article></div></section>
  <section id="seguranca" class="security"><div><span>SEGURANÇA DESDE A ARQUITETURA</span><h2>Dados de saúde tratados com a seriedade que merecem.</h2><p>Isolamento entre clínicas, permissões por perfil, registros clínicos protegidos e trilhas de auditoria.</p><ul><li>✓ Isolamento multi-tenant</li><li>✓ Controle por perfil e função</li><li>✓ Links públicos com token seguro</li><li>✓ Arquitetura preparada para LGPD</li></ul></div><div class="security-seal"><b>🔒</b><strong>Proteção em cada camada</strong><span>HTTPS · JWT · PBKDF2 · Auditoria</span></div></section>
  <section id="precos" class="pricing"><div class="section-title"><span>PLANOS TRANSPARENTES</span><h2>Escolha o ritmo do seu crescimento.</h2><p>Teste gratuitamente por 14 dias. Nenhum cartão é necessário.</p></div><div class="pricing-grid"><article><small>STARTER</small><h3>Para começar organizado</h3><div class="price"><sup>R$</sup><b>149</b><span>/mês</span></div><p>Para consultórios e equipes pequenas.</p><ul><li>✓ Até 3 profissionais</li><li>✓ Agenda e pacientes</li><li>✓ Prontuário eletrônico</li><li>✓ Financeiro essencial</li><li>✓ Confirmação por link</li></ul><button (click)="startTrial('starter')">Testar grátis</button></article><article class="featured"><em>MAIS ESCOLHIDO</em><small>PROFISSIONAL</small><h3>Gestão completa da clínica</h3><div class="price"><sup>R$</sup><b>299</b><span>/mês</span></div><p>Para clínicas multidisciplinares em expansão.</p><ul><li>✓ Até 15 profissionais</li><li>✓ Tudo do plano Starter</li><li>✓ Repasses profissionais</li><li>✓ Relatórios avançados</li><li>✓ Múltiplas unidades</li><li>✓ Suporte prioritário</li></ul><button (click)="startTrial('professional')">Começar teste gratuito</button></article><article class="enterprise"><small>ENTERPRISE</small><h3>Sob medida para sua rede</h3><div class="price"><b>Vamos conversar</b></div><p>Para redes, franquias e operações personalizadas.</p><ul><li>✓ Profissionais ilimitados</li><li>✓ White label</li><li>✓ Integrações personalizadas</li><li>✓ Migração assistida</li><li>✓ Atendimento dedicado</li></ul><a href="mailto:comercial@elloclinic.com.br?subject=Ello%20Clinic%20Enterprise">Consultar preço</a></article></div></section>
  <section id="trial" class="trial"><div><span>COMECE AGORA</span><h2>Sua clínica organizada em poucos minutos.</h2><p>Crie seu ambiente exclusivo e experimente todos os recursos por 14 dias.</p><div><b>14</b><span>dias grátis<br><small>sem cartão</small></span></div></div><form (ngSubmit)="createTrial()"><h3>Crie sua conta gratuita</h3><div class="trial-plan">Plano selecionado: <b>{{trial.plan==='starter'?'Starter':'Profissional'}}</b></div><label>Nome da clínica<input [(ngModel)]="trial.clinicName" name="clinicName" required placeholder="Ex.: Clínica Integrar"></label><label>Seu nome<input [(ngModel)]="trial.name" name="name" required placeholder="Nome completo"></label><div class="two-fields"><label>E-mail profissional<input [(ngModel)]="trial.email" name="trialEmail" type="email" required></label><label>Telefone<input [(ngModel)]="trial.phone" name="trialPhone" required placeholder="(11) 99999-9999"></label></div><label>Crie uma senha<input [(ngModel)]="trial.password" name="trialPassword" type="password" minlength="8" required placeholder="Mínimo de 8 caracteres"></label>@if(trialError()){<div class="error">{{trialError()}}</div>}<button class="landing-primary" [disabled]="trialLoading()">{{trialLoading()?'Criando sua clínica...':'Criar conta e testar grátis'}} →</button><small>Ao continuar, você concorda com os Termos de Uso e a Política de Privacidade.</small></form></section></main>
  <footer class="landing-footer"><div class="landing-logo"><b>e</b><span>ello<small>clinic</small></span></div><p>Gestão que conecta cuidado, pessoas e resultados.</p><span>© 2026 Ello Clinic</span></footer></div>
} @else if (publicToken) {
  <main class="confirmation-page"><section class="confirmation-card"><div class="confirm-brand"><div class="logo">e</div><span>ello <small>clinic</small></span></div>@if(publicLoading()){<div class="confirm-state"><div class="spinner"></div><h2>Carregando agendamento...</h2></div>}@else if(publicError()){<div class="confirm-state"><div class="state-icon error-icon">!</div><h2>Não foi possível abrir</h2><p>{{publicError()}}</p></div>}@else if(publicResult()){<div class="confirm-state"><div class="state-icon success-icon">✓</div><small>RESPOSTA REGISTRADA</small><h1>{{publicResult().message}}</h1><p>A clínica recebeu sua resposta. Você já pode fechar esta página.</p></div>}@else if(publicAppointment()){<div class="confirm-intro"><small>CONFIRMAÇÃO DE CONSULTA</small><h1>Olá, {{firstName(publicAppointment().patient)}}!</h1><p>Confira os detalhes abaixo e informe se poderá comparecer.</p></div><div class="confirm-details"><div><small>DATA</small><b>{{publicAppointment().startsAt | date:'EEEE, dd/MM/yyyy'}}</b></div><div><small>HORÁRIO</small><b>{{publicAppointment().startsAt | date:'HH:mm'}} às {{publicAppointment().endsAt | date:'HH:mm'}}</b></div><div><small>PROFISSIONAL</small><b>{{publicAppointment().professional}}</b></div><div><small>ATENDIMENTO</small><b>{{publicAppointment().service}}</b></div></div>@if(publicAppointment().responded){<div class="already-responded">Este agendamento já foi respondido: <b>{{publicResponseLabel(publicAppointment().response)}}</b>.</div>}@else{<label class="respondent">Seu nome ou nome do responsável<input [(ngModel)]="publicForm.respondentName" placeholder="Informe quem está respondendo"></label><div class="confirm-actions"><button class="confirm-yes" (click)="respondPublic('Confirmed')"><b>✓ Confirmar presença</b><small>Estarei presente neste horário</small></button><button (click)="selectPublicAction('RescheduleRequested')"><b>↻ Solicitar remarcação</b><small>Preciso de outra data ou horário</small></button><button class="confirm-no" (click)="selectPublicAction('CancellationRequested')"><b>× Solicitar cancelamento</b><small>Não poderei comparecer</small></button></div>@if(publicAction()){<div class="public-message"><label>Mensagem para a clínica<textarea [(ngModel)]="publicForm.message" placeholder="Conte brevemente sua necessidade"></textarea></label><div><button (click)="publicAction.set('')">Voltar</button><button class="primary" (click)="respondPublic(publicAction())">Enviar solicitação</button></div></div>}}}<footer>🔒 Link seguro · Seus dados são protegidos pela LGPD</footer></section></main>
} @else if (!token()) {
  <main class="login"><section class="brand-panel"><div class="logo">e</div><h1>Cuidado que conecta.</h1><p>Gestão inteligente para clínicas que enxergam cada paciente por inteiro.</p><div class="orb one"></div><div class="orb two"></div></section>
  <section class="login-form"><form (ngSubmit)="login()"><small>BEM-VINDO À ELLO</small><h2>Acesse sua clínica</h2><p>Organize sua rotina com leveza e segurança.</p><label>Clínica<input [(ngModel)]="credentials.tenant" name="tenant"></label><label>E-mail<input [(ngModel)]="credentials.email" name="email" type="email"></label><label>Senha<input [(ngModel)]="credentials.password" name="password" type="password"></label>@if(error()){<div class="error">{{error()}}</div>}<button [disabled]="loading()">{{loading()?'Entrando...':'Entrar na plataforma'}} <span>→</span></button><em>Ambiente protegido e em conformidade com a LGPD</em></form></section></main>
} @else {
  <div class="shell"><aside><div class="wordmark"><b>e</b><span>ello<small>clinic</small></span></div><nav>@for(item of allowedNav();track item.key){<button [class.active]="page()===item.key" (click)="page.set(item.key)"><i class="nav-icon">@switch(item.key){@case('dashboard'){<svg viewBox="0 0 24 24"><path d="m3 11 9-8 9 8"/><path d="M5 10v10h14V10"/><path d="M9 20v-6h6v6"/></svg>}@case('agenda'){<svg viewBox="0 0 24 24"><rect x="3" y="5" width="18" height="16" rx="2"/><path d="M16 3v4M8 3v4M3 10h18"/><path d="M8 14h.01M12 14h.01M16 14h.01M8 18h.01M12 18h.01"/></svg>}@case('pacientes'){<svg viewBox="0 0 24 24"><circle cx="12" cy="8" r="4"/><path d="M4.5 21a7.5 7.5 0 0 1 15 0"/></svg>}@case('profissionais'){<svg viewBox="0 0 24 24"><path d="M12 2v6M9 5h6"/><path d="M7 9h10l2 4-2 2 1 6H6l1-6-2-2 2-4Z"/><path d="M9 13h6"/></svg>}@case('prontuarios'){<svg viewBox="0 0 24 24"><path d="M6 3h12a2 2 0 0 1 2 2v16H6a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2Z"/><path d="M8 7h8M8 11h8M8 15h5"/></svg>}@case('repasses'){<svg viewBox="0 0 24 24"><circle cx="12" cy="12" r="9"/><path d="M16 8.5c-.8-.7-1.9-1-3.1-1-1.7 0-3 .8-3 2s1 1.8 3 2.3 3 1.1 3 2.4-1.4 2.3-3.2 2.3c-1.3 0-2.6-.4-3.6-1.2M12 5.5v13"/></svg>}@case('financeiro'){<svg viewBox="0 0 24 24"><rect x="3" y="6" width="18" height="14" rx="2"/><path d="M3 10h18M7 15h3"/></svg>}@case('relatorios'){<svg viewBox="0 0 24 24"><path d="M4 20V10M10 20V4M16 20v-7M22 20H2"/></svg>}@case('configuracoes'){<svg viewBox="0 0 24 24"><circle cx="12" cy="12" r="3"/><path d="M19.4 15a1.7 1.7 0 0 0 .3 1.9l.1.1-2.8 2.8-.1-.1a1.7 1.7 0 0 0-1.9-.3 1.7 1.7 0 0 0-1 1.6v.2h-4V21a1.7 1.7 0 0 0-1-1.6 1.7 1.7 0 0 0-1.9.3l-.1.1L4.2 17l.1-.1a1.7 1.7 0 0 0 .3-1.9A1.7 1.7 0 0 0 3 14H2.8v-4H3a1.7 1.7 0 0 0 1.6-1 1.7 1.7 0 0 0-.3-1.9L4.2 7 7 4.2l.1.1A1.7 1.7 0 0 0 9 4.6 1.7 1.7 0 0 0 10 3V2.8h4V3a1.7 1.7 0 0 0 1 1.6 1.7 1.7 0 0 0 1.9-.3l.1-.1L19.8 7l-.1.1a1.7 1.7 0 0 0-.3 1.9 1.7 1.7 0 0 0 1.6 1h.2v4H21a1.7 1.7 0 0 0-1.6 1Z"/></svg>}}</i>{{item.label}}</button>}</nav><div class="profile"><div>{{initials(user()?.name||'Usuário')}}</div><span><b>{{user()?.name||'Usuário'}}</b><small>{{roleLabel()}}</small></span><button (click)="logout()">↪</button></div></aside>
  <section class="content"><header><div><small>{{user()?.role==='Professional'?'ÁREA DO PROFISSIONAL':'GESTÃO DA CLÍNICA'}}</small><h1>{{title()}}</h1></div></header>
  @if(page()==='dashboard') {<div class="welcome"><div><small>VISÃO GERAL</small><h2>Olá, {{firstName(user()?.name)}}! <span>✦</span></h2><p>Você tem <b>{{dashboard()?.appointmentsToday || 0}} atendimentos</b> programados para hoje.</p></div><div class="pulse">◔<span>Rotina<br><b>organizada</b></span></div></div>
  <div class="metrics"><article><i class="mint">◷</i><span><small>ATENDIMENTOS HOJE</small><b>{{dashboard()?.appointmentsToday || 0}}</b><em>{{dashboard()?.confirmed || 0}} confirmados</em></span></article>@if(user()?.role!=='Professional'){<article><i class="peach">✓</i><span><small>RECEBIDO NO MÊS</small><b>{{dashboard()?.received || 0 | currency:'BRL'}}</b><em>Fluxo atualizado</em></span></article>}<article><i class="lavender">♙</i><span><small>PACIENTES ATIVOS</small><b>{{dashboard()?.activePatients || 0}}</b><em>Em acompanhamento</em></span></article>@if(user()?.role==='Professional'){<article><i class="yellow">◈</i><span><small>MEU REPASSE</small><b>{{settlements()?.net||0 | currency:'BRL'}}</b><em>Atendimentos finalizados</em></span></article>}@else{<article><i class="yellow">!</i><span><small>VALORES PENDENTES</small><b>{{dashboard()?.pending || 0 | currency:'BRL'}}</b><em>Requer atenção</em></span></article>}</div>
  <div class="grid"><article class="card schedule"><div class="card-title"><div><small>AGENDA DE HOJE</small><h3>Próximos atendimentos</h3></div><button (click)="page.set('agenda')">Ver agenda →</button></div>@for(a of todayAppointments();track a.id){<div class="appointment"><time>{{a.startsAt | date:'HH:mm'}}<small>{{a.endsAt | date:'HH:mm'}}</small></time><div class="avatar">{{initials(a.patient?.name)}}</div><span><b>{{a.patient?.name}}</b><small>{{a.service?.name}} · {{a.professional?.name}}</small></span><em>{{statusLabel(a.status)}}</em><button>•••</button></div>}@empty{<div class="empty">Nenhum atendimento encontrado para hoje.</div>}</article><article class="card quick"><small>ACESSO RÁPIDO</small><h3>O que você quer fazer?</h3>@if(user()?.role==='Professional'){<button (click)="page.set('prontuarios')"><i>▤</i><span><b>Registrar evolução</b><small>Documente um atendimento</small></span>→</button><button (click)="page.set('agenda')"><i>▦</i><span><b>Minha agenda</b><small>Consulte seus horários</small></span>→</button><button (click)="page.set('repasses')"><i>◈</i><span><b>Meus repasses</b><small>Consulte valores previstos</small></span>→</button>}@else{<button (click)="page.set('pacientes')"><i>♙</i><span><b>Novo paciente</b><small>Cadastre um novo paciente</small></span>→</button><button (click)="page.set('agenda')"><i>▦</i><span><b>Agendar consulta</b><small>Encontre um horário disponível</small></span>→</button><button (click)="page.set('financeiro')"><i>◈</i><span><b>Registrar pagamento</b><small>Atualize o financeiro</small></span>→</button>}</article></div>}
  @else if(page()==='agenda') {
    <article class="card agenda-module"><div class="card-title agenda-title"><div><small>AGENDA CLÍNICA</small><h3>{{weekLabel()}}</h3></div><div class="agenda-nav"><button (click)="changeWeek(-1)">‹</button><button (click)="goToday()">Hoje</button><button (click)="changeWeek(1)">›</button><button class="primary" (click)="openForm('appointment')">＋ Novo agendamento</button></div></div>
    <div class="agenda-filters"><label>Profissional<select [(ngModel)]="agendaProfessional"><option value="">Todos</option>@for(p of professionals();track p.id){<option [value]="p.id">{{p.name}}</option>}</select></label><label>Status<select [(ngModel)]="agendaStatus"><option value="">Todos</option>@for(s of appointmentStatuses;track s.value){<option [value]="s.value">{{s.label}}</option>}</select></label><span class="legend"><i></i> {{filteredAppointments().length}} atendimento(s) na semana</span></div>
    <div class="week-grid">@for(day of weekDays();track day.toISOString()){<section [class.today]="isToday(day)"><header><small>{{dayName(day)}}</small><b>{{day | date:'dd'}}</b></header><div class="day-events">@for(a of appointmentsForDay(day);track a.id){<button class="event" [style.border-left-color]="a.professional?.color || '#246b5d'" (click)="editAppointment(a)"><time>{{a.startsAt | date:'HH:mm'}}–{{a.endsAt | date:'HH:mm'}}</time><b>{{a.patient?.name}}</b><small>{{a.service?.name}}</small><em [class]="'status '+a.status">{{statusLabel(a.status)}}</em></button>}@empty{<div class="day-empty">Livre</div>}</div></section>}</div>
    <div class="agenda-list"><div class="card-title"><div><small>RESUMO DA SEMANA</small><h3>Todos os atendimentos</h3></div>@if(toast()){<span class="toast">✓ {{toast()}}</span>}</div><div class="data-table"><div class="tr head appointment-row"><span>Data e hora</span><span>Paciente</span><span>Profissional</span><span>Serviço</span><span>Status</span><span>Ações</span></div>@for(a of filteredAppointments();track a.id){<div class="tr appointment-row"><span><b>{{a.startsAt | date:'dd/MM'}}</b> · {{a.startsAt | date:'HH:mm'}}</span><span>{{a.patient?.name}}</span><span>{{a.professional?.name}}</span><span>{{a.service?.name}}</span><span><em>{{statusLabel(a.status)}}</em></span><span class="actions appointment-actions">@if(user()?.role!=='Professional'){<button class="share-button" title="Compartilhar confirmação" (click)="shareAppointment(a)">↗ <span>Compartilhar</span></button>}<button title="Editar" (click)="editAppointment(a)">✎</button>@if(user()?.role!=='Professional'){<button class="danger" title="Cancelar" (click)="cancelAppointment(a)">×</button>}</span></div>}@empty{<div class="empty">Nenhum atendimento nesta semana.</div>}</div></div></article>
  } @else if(page()==='pacientes' || page()==='profissionais') {
    <article class="card module"><div class="card-title"><div><small>CADASTROS</small><h3>{{title()}}</h3></div>@if(user()?.role!=='Professional'){<button class="primary" (click)="openForm(page()==='pacientes'?'patient':'professional')">＋ Adicionar</button>}</div>
    <div class="toolbar"><input placeholder="Buscar por nome..." [(ngModel)]="search" (ngModelChange)="loadRegistrations()"><span>{{currentRows().length}} registro(s)</span></div>
    <div class="data-table"><div class="tr head"><span>Nome</span><span>Contato</span><span>{{page()==='pacientes'?'Responsável':'Conselho / Especialidade'}}</span><span>Status</span><span>Ações</span></div>
    @for(row of currentRows();track row.id){<div class="tr"><span><div class="person"><div class="avatar">{{initials(row.name)}}</div><b>{{row.name}}</b></div><small>{{row.document || row.registrationNumber || 'Sem documento'}}</small></span><span>{{row.phone || row.email || 'Não informado'}}</span><span>{{page()==='pacientes'?(row.responsibleName || '—'):professionalDetail(row)}}</span><span><em [class.inactive]="!row.active">{{row.active?'Ativo':'Inativo'}}</em></span><span class="actions">@if(user()?.role!=='Professional'){@if(page()==='profissionais'){<button [class.access-ready]="row.hasAccess" [title]="row.hasAccess?'Redefinir acesso':'Criar acesso'" (click)="openAccess(row)">🔑</button>}<button (click)="editRow(row)">✎</button><button class="danger" (click)="removeRow(row)">×</button>}</span></div>}@empty{<div class="empty">Nenhum cadastro encontrado.</div>}</div></article>
  } @else if(page()==='configuracoes') {
    <article class="card module"><div class="card-title"><div><small>ESTRUTURA DA CLÍNICA</small><h3>Configurações</h3></div><button class="primary" (click)="openForm(configTab())">＋ Adicionar</button></div>
    <div class="tabs">@for(tab of configTabs;track tab.key){<button [class.active]="configTab()===tab.key" (click)="configTab.set(tab.key)">{{tab.label}}</button>}</div>
    <div class="data-table"><div class="tr head config"><span>Nome</span><span>Detalhes</span><span>Status</span><span>Ações</span></div>@for(row of configRows();track row.id){<div class="tr config"><span><b>{{row.name}}</b></span><span>{{configDetail(row)}}</span><span><em [class.inactive]="!row.active">{{row.active?'Ativo':'Inativo'}}</em></span><span class="actions"><button (click)="editConfig(row)">✎</button><button class="danger" (click)="removeConfig(row)">×</button></span></div>}@empty{<div class="empty">Nenhum item cadastrado nesta categoria.</div>}</div></article>
  } @else if(page()==='prontuarios') {
    <div class="records-layout"><article class="card records-list"><div class="card-title"><div><small>PRONTUÁRIOS</small><h3>Pacientes</h3></div></div><input class="record-search" placeholder="Buscar paciente..." [(ngModel)]="recordSearch">@for(row of filteredRecords();track row.patient.id){<button [class.active]="selectedRecord()?.patient?.id===row.patient.id" (click)="selectRecord(row.patient.id)"><div class="avatar">{{initials(row.patient.name)}}</div><span><b>{{row.patient.name}}</b><small>{{row.evolutions}} evolução(ões) · {{row.appointments}} atendimento(s)</small></span>@if(row.pendingEvolution){<em>{{row.pendingEvolution}} pendente(s)</em>}</button>}@empty{<div class="empty">Nenhum paciente disponível.</div>}</article>
    <article class="card record-detail">@if(selectedRecord()){<div class="record-head"><div><small>PRONTUÁRIO ELETRÔNICO</small><h2>{{selectedRecord().patient.name}}</h2><p>{{selectedRecord().patient.phone||'Sem telefone'}} · {{selectedRecord().patient.responsibleName||'Sem responsável informado'}}</p></div><div><button (click)="openEvolutionForRecord()">＋ Evolução</button><button class="primary" (click)="openPlanForRecord()">＋ Plano terapêutico</button></div></div><div class="record-tabs">@for(tab of recordTabs;track tab.key){<button [class.active]="recordTab()===tab.key" (click)="recordTab.set(tab.key)">{{tab.label}}</button>}</div>
    @if(recordTab()==='timeline'){<div class="timeline">@for(a of selectedRecord().appointments;track a.id){<div class="timeline-item"><i [class.done]="a.status==='Completed'||a.status==='Finalized'"></i><div><small>{{a.startsAt | date:'dd/MM/yyyy · HH:mm'}}</small><h4>{{a.service?.name}} · {{a.professional?.name}}</h4><p>Status: {{statusLabel(a.status)}}</p>@if(evolutionForAppointment(a.id);as evolution){<section><b>Objetivo</b><p>{{evolution.objective}}</p><b>Conduta</b><p>{{evolution.conduct}}</p><em>{{evolution.finalized?'Registro finalizado':'Rascunho'}}</em></section>}@else if(a.status==='Completed'){<button (click)="openEvolutionForAppointment(a)">Registrar evolução pendente</button>}</div></div>}@empty{<div class="empty">Nenhum atendimento no histórico.</div>}</div>}
    @else if(recordTab()==='evolutions'){<div class="evolution-cards">@for(row of selectedRecord().evolutions;track row.id){<section><header><span><b>{{row.createdAt | date:'dd/MM/yyyy HH:mm'}}</b><small>{{professionalName(row.professionalId)}}</small></span><em>{{row.finalized?'Finalizada':'Rascunho'}}</em></header><h4>Objetivo</h4><p>{{row.objective}}</p><h4>Atividades e resposta</h4><p>{{row.activities}} — {{row.response}}</p><h4>Conduta</h4><p>{{row.conduct}}</p>@if(!row.finalized){<button (click)="editEvolution(row)">Editar rascunho</button>}</section>}@empty{<div class="empty">Nenhuma evolução registrada.</div>}</div>}
    @else{<div class="plan-cards">@for(plan of selectedRecord().plans;track plan.id){<section><header><div><small>INÍCIO {{plan.startDate | date:'dd/MM/yyyy'}}</small><h3>{{specialtyName(plan.specialtyId)}}</h3></div><em>{{planStatusLabel(plan.status)}}</em></header><b>Queixa principal</b><p>{{plan.mainComplaint}}</p><b>Objetivos gerais</b><p>{{plan.generalGoals}}</p><b>Objetivos específicos</b><p>{{plan.specificGoals}}</p><footer><span>Frequência: {{plan.recommendedFrequency}}</span><span>Reavaliação: {{plan.reassessmentDate | date:'dd/MM/yyyy'}}</span><button (click)="editPlan(plan)">Editar</button></footer></section>}@empty{<div class="empty">Nenhum plano terapêutico cadastrado.</div>}</div>}}@else{<div class="module-body"><div class="big-icon">▤</div><h2>Selecione um paciente</h2><p>Consulte o histórico clínico, evoluções e planos terapêuticos.</p></div>}</article></div>
  } @else if(page()==='repasses' && user()?.role==='Professional') {
    <article class="card module"><div class="card-title"><div><small>MEUS REPASSES</small><h3>Resumo financeiro</h3></div></div><div class="settlement-summary"><div><small>VALOR BRUTO</small><b>{{settlements()?.gross||0 | currency:'BRL'}}</b></div><div><small>PERCENTUAL</small><b>{{settlements()?.percent||0}}%</b></div><div><small>VALOR LÍQUIDO</small><b>{{settlements()?.net||0 | currency:'BRL'}}</b></div></div><div class="data-table"><div class="tr head settlement-row"><span>Data</span><span>Paciente</span><span>Serviço</span><span>Bruto</span><span>Repasse</span></div>@for(row of settlements()?.items||[];track row.id){<div class="tr settlement-row"><span>{{row.startsAt | date:'dd/MM/yyyy'}}</span><span>{{row.patient}}</span><span>{{row.service}}</span><span>{{row.gross | currency:'BRL'}}</span><span><b>{{row.net | currency:'BRL'}}</b></span></div>}@empty{<div class="empty">Nenhum atendimento finalizado para repasse.</div>}</div></article>
  } @else if(page()==='relatorios') {
    <article class="card reports"><div class="card-title"><div><small>ANÁLISE OPERACIONAL</small><h3>Relatórios da clínica</h3></div><button (click)="exportReportCsv()">↓ Exportar CSV</button></div><div class="report-filters"><label>Data inicial<input type="date" [(ngModel)]="reportFrom"></label><label>Data final<input type="date" [(ngModel)]="reportTo"></label><button class="primary" (click)="loadReports()">Atualizar relatório</button></div>@if(reportData()){<div class="report-metrics"><article><small>ATENDIMENTOS</small><b>{{reportData().summary.appointments}}</b><em>{{reportData().summary.completed}} realizados</em></article><article><small>TAXA DE REALIZAÇÃO</small><b>{{reportData().summary.occupancyRate}}%</b><em>{{reportData().summary.cancelled}} cancelamentos</em></article><article><small>RECEITA RECEBIDA</small><b>{{reportData().summary.revenue | currency:'BRL'}}</b><em>{{reportData().summary.pending | currency:'BRL'}} pendente</em></article><article><small>RESULTADO</small><b>{{reportData().summary.revenue-reportData().summary.expenses | currency:'BRL'}}</b><em>{{reportData().summary.expenses | currency:'BRL'}} despesas</em></article></div><div class="report-grid"><section><div class="card-title"><h3>Atendimentos por profissional</h3></div>@for(row of reportData().byProfessional;track row.id){<div class="bar-row"><span>{{row.name}}</span><div><i [style.width.%]="reportBar(row.appointments,'byProfessional')"></i></div><b>{{row.appointments}}</b></div>}@empty{<div class="empty">Sem dados no período.</div>}</section><section><div class="card-title"><h3>Distribuição por status</h3></div>@for(row of reportData().byStatus;track row.status){<div class="bar-row"><span>{{statusLabel(row.status)}}</span><div><i class="alt" [style.width.%]="reportBar(row.count,'byStatus')"></i></div><b>{{row.count}}</b></div>}@empty{<div class="empty">Sem dados no período.</div>}</section></div><div class="data-table"><div class="tr head service-report-row"><span>Serviço</span><span>Atendimentos</span><span>Receita prevista</span></div>@for(row of reportData().byService;track row.id){<div class="tr service-report-row"><span><b>{{row.name}}</b></span><span>{{row.appointments}}</span><span>{{row.revenue | currency:'BRL'}}</span></div>}</div>}@else{<div class="empty">Selecione o período e atualize o relatório.</div>}</article>
  } @else if(page()==='financeiro') {
    <article class="card module"><div class="card-title"><div><small>CONTROLE FINANCEIRO</small><h3>Contas a pagar</h3></div><button class="primary" (click)="openForm('payable')">＋ Nova despesa</button></div>
    <div class="data-table"><div class="tr head finance"><span>Descrição</span><span>Categoria</span><span>Vencimento</span><span>Valor</span><span>Status</span><span>Ações</span></div>@for(row of payables();track row.id){<div class="tr finance"><span><b>{{row.description}}</b></span><span>{{row.category}}</span><span>{{row.dueDate | date:'dd/MM/yyyy'}}</span><span>{{row.amount | currency:'BRL'}}</span><span><em>{{financialLabel(row.status)}}</em></span><span class="actions"><button (click)="editPayable(row)">✎</button><button class="danger" (click)="removePayable(row)">×</button></span></div>}@empty{<div class="empty">Nenhuma despesa cadastrada.</div>}</div></article>
  } @else {<article class="card module"><div class="module-body"><h2>{{title()}}</h2><p>Este fluxo será disponibilizado na próxima etapa do MVP.</p></div></article>}
  @if(formOpen()){<div class="modal-backdrop" (click)="closeForm($event)"><form class="modal" (ngSubmit)="saveForm()" (click)="$event.stopPropagation()"><div class="modal-head"><div><small>{{editingId()?'EDITAR REGISTRO':'NOVO REGISTRO'}}</small><h2>{{formTitle()}}</h2></div><button type="button" (click)="formOpen.set(false)">×</button></div><div class="form-grid">
    @for(field of formFields();track field.key){<label [class.full]="field.full">{{field.label}}@if(field.type==='select'){<select [(ngModel)]="formData[field.key]" [name]="field.key" [required]="field.required"><option value="">Selecione</option>@for(option of field.options || [];track option.value){<option [value]="option.value">{{option.label}}</option>}</select>}@else if(field.type==='textarea'){<textarea [(ngModel)]="formData[field.key]" [name]="field.key" [required]="field.required" [placeholder]="field.placeholder || ''"></textarea>}@else if(field.type==='checkbox'){<input class="check" type="checkbox" [(ngModel)]="formData[field.key]" [name]="field.key">}@else{<input [type]="field.type || 'text'" [(ngModel)]="formData[field.key]" [name]="field.key" [required]="field.required" [placeholder]="field.placeholder || ''">}</label>}
    </div>@if(formError()){<div class="error">{{formError()}}</div>}<div class="modal-actions"><button type="button" (click)="formOpen.set(false)">Cancelar</button><button class="primary" [disabled]="saving()">{{saving()?'Salvando...':'Salvar cadastro'}}</button></div></form></div>}
  </section></div>}
`})
class App {
  private http = inject(HttpClient);
  isLanding = location.pathname==='/inicio' || (location.pathname==='/' && !localStorage.getItem('ello_token'));
  trial={clinicName:'',name:'',email:'',phone:'',password:'',plan:'professional'}; trialLoading=signal(false); trialError=signal('');
  publicToken = location.pathname.startsWith('/confirmacao/') ? decodeURIComponent(location.pathname.split('/').pop() || '') : '';
  publicAppointment = signal<any>(null); publicLoading = signal(false); publicError = signal(''); publicResult = signal<any>(null); publicAction = signal(''); toast = signal(''); publicForm={respondentName:'',message:''};
  token = signal(localStorage.getItem('ello_token')); user = signal<any>(JSON.parse(localStorage.getItem('ello_user')||'null')); loading = signal(false); error = signal(''); page = signal('dashboard'); dashboard = signal<any>(null);
  appointments = signal<any[]>([]); patients = signal<any[]>([]); professionals = signal<any[]>([]); catalog = signal<any>({specialties:[],services:[],units:[],rooms:[]}); payables = signal<any[]>([]);
  evolutions = signal<any[]>([]); settlements = signal<any>(null);
  medicalRecords = signal<any[]>([]); selectedRecord = signal<any>(null); recordTab = signal('timeline'); recordSearch = ''; recordTabs=[{key:'timeline',label:'Linha do tempo'},{key:'evolutions',label:'Evoluções'},{key:'plans',label:'Plano terapêutico'}];
  reportData = signal<any>(null); reportFrom = new Date(new Date().getFullYear(),new Date().getMonth(),1).toISOString().slice(0,10); reportTo = new Date().toISOString().slice(0,10);
  weekStart = signal(this.startOfWeek(new Date())); agendaProfessional = ''; agendaStatus = '';
  formOpen = signal(false); formKind = signal(''); editingId = signal<string|null>(null); formError = signal(''); saving = signal(false); configTab = signal('specialty'); search = '';
  formData: Record<string, any> = {}; credentials={tenant:'',email:'',password:''};
  nav=[{key:'dashboard',label:'Visão geral'},{key:'agenda',label:'Agenda'},{key:'pacientes',label:'Pacientes'},{key:'profissionais',label:'Profissionais'},{key:'prontuarios',label:'Prontuários'},{key:'repasses',label:'Meus repasses'},{key:'financeiro',label:'Financeiro'},{key:'relatorios',label:'Relatórios'},{key:'configuracoes',label:'Configurações'}];
  configTabs=[{key:'specialty',label:'Especialidades'},{key:'service',label:'Serviços'},{key:'unit',label:'Unidades'},{key:'room',label:'Salas'}];
  appointmentStatuses=[{value:'PreScheduled',label:'Pré-agendado'},{value:'AwaitingConfirmation',label:'Aguardando confirmação'},{value:'Confirmed',label:'Confirmado'},{value:'Arrived',label:'Paciente chegou'},{value:'InProgress',label:'Em atendimento'},{value:'Completed',label:'Realizado'},{value:'PatientCancelled',label:'Cancelado pelo paciente'},{value:'NoShow',label:'Falta'},{value:'AwaitingPayment',label:'Aguardando pagamento'},{value:'Finalized',label:'Finalizado'}];
  constructor(){ if(this.publicToken)this.loadPublic();else if(this.token()){if(!this.user())this.http.get<any>(api+'/me').subscribe(x=>{this.user.set(x);localStorage.setItem('ello_user',JSON.stringify(x));this.load()});else this.load()} }
  openLogin(){location.href='/login'}
  startTrial(plan:string){this.trial.plan=plan;setTimeout(()=>document.getElementById('trial')?.scrollIntoView({behavior:'smooth'}))}
  createTrial(){this.trialLoading.set(true);this.trialError.set('');this.http.post<any>(api+'/public/trials',this.trial).subscribe({next:r=>{localStorage.setItem('ello_token',r.token);localStorage.setItem('ello_user',JSON.stringify(r.user));this.token.set(r.token);this.user.set(r.user);this.isLanding=false;this.trialLoading.set(false);history.replaceState({},'', '/app');this.page.set('dashboard');this.load()},error:e=>{this.trialError.set(e.error?.message||'Não foi possível criar o trial. Tente novamente.');this.trialLoading.set(false)}})}
  title(){return this.nav.find(x=>x.key===this.page())?.label||''} navItem(){return this.nav.find(x=>x.key===this.page())}
  allowedNav(){const professional=this.user()?.role==='Professional';return this.nav.filter(x=>professional?['dashboard','agenda','pacientes','prontuarios','repasses'].includes(x.key):x.key!=='repasses')}
  roleLabel(){return ({Professional:'Profissional',ClinicAdmin:'Administrador',Reception:'Recepção',Finance:'Financeiro'} as any)[this.user()?.role]||'Clínica Ello'}
  login(){this.loading.set(true);this.error.set('');this.http.post<any>(api+'/auth/login',this.credentials).subscribe({next:r=>{localStorage.setItem('ello_token',r.token);localStorage.setItem('ello_user',JSON.stringify(r.user));this.token.set(r.token);this.user.set(r.user);this.loading.set(false);this.page.set('dashboard');this.load()},error:()=>{this.error.set('Não foi possível entrar. Confira seus dados.');this.loading.set(false)}})}
  logout(){localStorage.removeItem('ello_token');localStorage.removeItem('ello_user');this.token.set(null);this.user.set(null)}
  load(){this.http.get(api+'/dashboard').subscribe(x=>this.dashboard.set(x));this.loadAgenda();this.loadRegistrations();this.loadCatalog();this.loadMedicalRecords();if(this.user()?.role!=='Professional'){this.loadFinance();this.loadReports()}else{this.loadEvolutions();this.loadSettlements()}}
  loadAgenda(){const from=this.weekStart(),to=new Date(from);to.setDate(to.getDate()+7);this.http.get<any[]>(api+`/appointments?from=${from.toISOString()}&to=${to.toISOString()}`).subscribe(x=>this.appointments.set(x))}
  loadRegistrations(){this.http.get<any[]>(api+`/patients?search=${encodeURIComponent(this.search)}`).subscribe(x=>this.patients.set(x));this.http.get<any[]>(api+'/professionals').subscribe(x=>this.professionals.set(x))}
  loadCatalog(){this.http.get<any>(api+'/catalog').subscribe(x=>this.catalog.set(x))}
  loadFinance(){this.http.get<any>(api+'/finance').subscribe(x=>this.payables.set(x.payables))}
  loadEvolutions(){this.http.get<any[]>(api+'/evolutions').subscribe(x=>this.evolutions.set(x))}
  loadSettlements(){this.http.get<any>(api+'/professional/me/settlements').subscribe(x=>this.settlements.set(x))}
  loadMedicalRecords(){this.http.get<any[]>(api+'/medical-records').subscribe(x=>{this.medicalRecords.set(x);if(!this.selectedRecord()&&x.length)this.selectRecord(x[0].patient.id)})}
  filteredRecords(){const term=this.recordSearch.trim().toLowerCase();return this.medicalRecords().filter(x=>!term||x.patient.name.toLowerCase().includes(term))}
  selectRecord(id:string){this.http.get<any>(`${api}/medical-records/${id}`).subscribe(x=>{this.selectedRecord.set(x);this.recordTab.set('timeline')})}
  currentRows(){return this.page()==='pacientes'?this.patients():this.professionals()}
  configRows(){const c=this.catalog();return this.configTab()==='specialty'?c.specialties:this.configTab()==='service'?c.services:this.configTab()==='unit'?c.units:c.rooms}
  initials(n=''){return n.split(' ').slice(0,2).map((x:string)=>x[0]).join('')}
  statusLabel(s:string){return this.appointmentStatuses.find(x=>x.value===s)?.label||({ClinicCancelled:'Cancelado pela clínica',Rescheduled:'Remarcado'} as any)[s]||s}
  financialLabel(s:string){return ({Pending:'Pendente',Paid:'Pago',PartiallyPaid:'Parcial',Overdue:'Vencido',Cancelled:'Cancelado'} as any)[s]||s}
  specialtyName(id:string){return this.catalog().specialties.find((x:any)=>x.id===id)?.name||'Não definida'}
  unitName(id:string){return this.catalog().units.find((x:any)=>x.id===id)?.name||'Não definida'}
  professionalDetail(row:any){return `${row.council||'Sem conselho'} · ${this.specialtyName(row.specialtyId)}`}
  configDetail(row:any){if(this.configTab()==='service')return `${this.specialtyName(row.specialtyId)} · ${row.durationMinutes} min · ${Number(row.price).toLocaleString('pt-BR',{style:'currency',currency:'BRL'})}`;if(this.configTab()==='unit')return row.address||'Sem endereço';if(this.configTab()==='room')return this.unitName(row.unitId);return row.color}
  formTitle(){return ({plan:'Plano terapêutico',access:'Acesso do profissional',evolution:'Evolução clínica',appointment:'Agendamento',patient:'Paciente',professional:'Profissional',specialty:'Especialidade',service:'Serviço',unit:'Unidade',room:'Sala',payable:'Despesa'} as any)[this.formKind()]||'Cadastro'}
  formFields():any[]{const opts=(items:any[])=>items.filter(x=>x.active!==false).map(x=>({value:x.id,label:x.name}));const appointmentOptions=this.appointments().filter(x=>!this.user()?.professionalId||x.professionalId===this.user().professionalId).map(x=>({value:x.id,label:`${new Date(x.startsAt).toLocaleDateString('pt-BR')} · ${x.patient?.name}`}));const professionalField=this.user()?.role==='Professional'?[]:[{key:'professionalId',label:'Profissional',type:'select',required:true,options:opts(this.professionals())}];const fields:any={plan:[...professionalField,{key:'specialtyId',label:'Especialidade',type:'select',required:true,options:opts(this.catalog().specialties)},{key:'startDate',label:'Data de início',type:'date',required:true},{key:'mainComplaint',label:'Queixa principal',type:'textarea',required:true,full:true},{key:'generalGoals',label:'Objetivos gerais',type:'textarea',required:true,full:true},{key:'specificGoals',label:'Objetivos específicos',type:'textarea',required:true,full:true},{key:'recommendedFrequency',label:'Frequência recomendada',required:true},{key:'reassessmentDate',label:'Data de reavaliação',type:'date'},{key:'status',label:'Status',type:'select',required:true,options:[{value:'Active',label:'Ativo'},{value:'Paused',label:'Pausado'},{value:'Completed',label:'Concluído'}]}],access:[{key:'email',label:'E-mail de acesso',type:'email',required:true},{key:'password',label:'Senha temporária',type:'password',required:true,placeholder:'Mínimo de 8 caracteres'}],evolution:[...professionalField,{key:'patientId',label:'Paciente',type:'select',required:true,options:opts(this.patients())},{key:'appointmentId',label:'Atendimento',type:'select',required:true,options:appointmentOptions},{key:'objective',label:'Objetivo da sessão',type:'textarea',required:true,full:true},{key:'activities',label:'Atividades realizadas',type:'textarea',required:true,full:true},{key:'response',label:'Resposta do paciente',type:'textarea',required:true,full:true},{key:'conduct',label:'Conduta e próximos passos',type:'textarea',required:true,full:true},{key:'finalized',label:'Finalizar evolução',type:'checkbox'}],appointment:[{key:'patientId',label:'Paciente',type:'select',required:true,options:opts(this.patients())},{key:'professionalId',label:'Profissional',type:'select',required:true,options:opts(this.professionals())},{key:'serviceId',label:'Serviço',type:'select',required:true,options:opts(this.catalog().services)},{key:'unitId',label:'Unidade',type:'select',required:true,options:opts(this.catalog().units)},{key:'roomId',label:'Sala',type:'select',options:opts(this.catalog().rooms)},{key:'status',label:'Status',type:'select',required:true,options:this.appointmentStatuses},{key:'startsAt',label:'Início',type:'datetime-local',required:true},{key:'endsAt',label:'Término',type:'datetime-local',required:true},{key:'amount',label:'Valor',type:'number',required:true},{key:'notes',label:'Observações administrativas',full:true}],patient:[{key:'name',label:'Nome completo',required:true},{key:'document',label:'CPF'},{key:'birthDate',label:'Nascimento',type:'date'},{key:'phone',label:'Telefone'},{key:'email',label:'E-mail',type:'email'},{key:'responsibleName',label:'Responsável'},{key:'responsiblePhone',label:'Telefone do responsável'},{key:'notes',label:'Observações',full:true}],professional:[{key:'name',label:'Nome completo',required:true},{key:'email',label:'E-mail',type:'email',required:true},{key:'phone',label:'Telefone'},{key:'specialtyId',label:'Especialidade',type:'select',required:true,options:opts(this.catalog().specialties)},{key:'council',label:'Conselho'},{key:'registrationNumber',label:'Registro profissional'},{key:'defaultSplitPercent',label:'Repasse (%)',type:'number'},{key:'color',label:'Cor da agenda',type:'color'}],specialty:[{key:'name',label:'Nome',required:true},{key:'color',label:'Cor',type:'color'}],service:[{key:'name',label:'Nome',required:true},{key:'specialtyId',label:'Especialidade',type:'select',required:true,options:opts(this.catalog().specialties)},{key:'durationMinutes',label:'Duração (min)',type:'number',required:true},{key:'price',label:'Valor',type:'number',required:true},{key:'requiresRoom',label:'Exige sala',type:'checkbox'}],unit:[{key:'name',label:'Nome',required:true},{key:'address',label:'Endereço',full:true}],room:[{key:'name',label:'Nome',required:true},{key:'unitId',label:'Unidade',type:'select',required:true,options:opts(this.catalog().units)}],payable:[{key:'description',label:'Descrição',required:true},{key:'category',label:'Categoria',required:true},{key:'amount',label:'Valor',type:'number',required:true},{key:'dueDate',label:'Vencimento',type:'date',required:true},{key:'status',label:'Status',type:'select',required:true,options:[{value:'Pending',label:'Pendente'},{value:'Paid',label:'Pago'},{value:'Overdue',label:'Vencido'},{value:'Cancelled',label:'Cancelado'}]}]};return fields[this.formKind()]||[]}
  openForm(kind:string,row?:any){this.formKind.set(kind);this.editingId.set(row?.id||null);this.formError.set('');this.formData=row?{...row}:this.defaults(kind);this.formOpen.set(true)}
  defaults(kind:string){const base:any={active:true};if(kind==='plan')Object.assign(base,{patientId:this.selectedRecord()?.patient?.id||'',professionalId:this.user()?.professionalId||'',startDate:new Date().toISOString().slice(0,10),status:'Active'});if(kind==='evolution')Object.assign(base,{patientId:this.selectedRecord()?.patient?.id||'',professionalId:this.user()?.professionalId||'',finalized:false});if(kind==='appointment'){const start=new Date();start.setMinutes(Math.ceil(start.getMinutes()/30)*30,0,0);const end=new Date(start.getTime()+50*60000);Object.assign(base,{startsAt:this.toLocalInput(start),endsAt:this.toLocalInput(end),status:'AwaitingConfirmation',amount:0,professionalId:this.user()?.professionalId||''})}if(kind==='professional')Object.assign(base,{color:'#4F7CF7',defaultSplitPercent:50});if(kind==='specialty')base.color='#7158E2';if(kind==='service')Object.assign(base,{durationMinutes:50,price:0,requiresRoom:true});if(kind==='payable')Object.assign(base,{dueDate:new Date().toISOString().slice(0,10),status:'Pending',amount:0});return base}
  editRow(row:any){this.openForm(this.page()==='pacientes'?'patient':'professional',row)} editConfig(row:any){this.openForm(this.configTab(),row)} editPayable(row:any){this.openForm('payable',row)}
  endpoint(kind=this.formKind()){return ({plan:'therapeutic-plans',evolution:'evolutions',appointment:'appointments',patient:'patients',professional:'professionals',specialty:'specialties',service:'services',unit:'units',room:'rooms',payable:'payables'} as any)[kind]}
  saveForm(){this.saving.set(true);this.formError.set('');const isAccess=this.formKind()==='access';const url=isAccess?`${api}/professionals/${this.editingId()}/access`:`${api}/${this.endpoint()}${this.editingId()?'/'+this.editingId():''}`;const data={...this.formData};if(this.formKind()==='appointment'){data['startsAt']=new Date(data['startsAt']).toISOString();data['endsAt']=new Date(data['endsAt']).toISOString();data['amount']=Number(data['amount'])}if(['evolution','plan'].includes(this.formKind())&&this.user()?.professionalId)data['professionalId']=this.user().professionalId;const request=isAccess||!this.editingId()?this.http.post(url,data):this.http.put(url,data);request.subscribe({next:()=>{this.saving.set(false);this.formOpen.set(false);this.refreshKind()},error:e=>{this.saving.set(false);this.formError.set(e.error?.message||e.error?.title||'Não foi possível salvar o cadastro.')}})}
  refreshKind(){if(this.formKind()==='access')this.loadRegistrations();else if(['evolution','plan'].includes(this.formKind())){this.loadEvolutions();const id=this.selectedRecord()?.patient?.id;if(id)this.selectRecord(id);this.loadMedicalRecords()}else if(this.formKind()==='appointment')this.loadAgenda();else if(['patient','professional'].includes(this.formKind()))this.loadRegistrations();else if(this.formKind()==='payable')this.loadFinance();else this.loadCatalog()}
  removeRow(row:any){if(!confirm(`Deseja inativar ${row.name}?`))return;this.http.delete(`${api}/${this.endpoint(this.page()==='pacientes'?'patient':'professional')}/${row.id}`).subscribe(()=>this.loadRegistrations())}
  removeConfig(row:any){if(!confirm(`Deseja excluir ${row.name}?`))return;this.http.delete(`${api}/${this.endpoint(this.configTab())}/${row.id}`).subscribe({next:()=>this.loadCatalog(),error:e=>alert(e.error?.message||'Este item está em uso e não pode ser excluído.')})}
  removePayable(row:any){if(!confirm(`Deseja excluir a despesa ${row.description}?`))return;this.http.delete(`${api}/payables/${row.id}`).subscribe(()=>this.loadFinance())}
  openAccess(row:any){this.formKind.set('access');this.editingId.set(row.id);this.formData={email:row.email,password:''};this.formError.set('');this.formOpen.set(true)}
  patientName(id:string){return this.patients().find(x=>x.id===id)?.name||'Paciente'}
  professionalName(id:string){return this.professionals().find(x=>x.id===id)?.name||'Profissional'}
  evolutionForAppointment(id:string){return this.selectedRecord()?.evolutions?.find((x:any)=>x.appointmentId===id)}
  openEvolutionForRecord(){this.openForm('evolution',{...this.defaults('evolution')})}
  openEvolutionForAppointment(a:any){this.openForm('evolution',{...this.defaults('evolution'),patientId:a.patientId,appointmentId:a.id,professionalId:a.professionalId})}
  editEvolution(row:any){this.openForm('evolution',row)}
  openPlanForRecord(){this.openForm('plan',{...this.defaults('plan')})}
  editPlan(row:any){this.openForm('plan',row)}
  planStatusLabel(value:string){return ({Active:'Ativo',Paused:'Pausado',Completed:'Concluído'} as any)[value]||value}
  loadReports(){const from=new Date(`${this.reportFrom}T00:00:00`);const to=new Date(`${this.reportTo}T23:59:59`);this.http.get<any>(`${api}/reports?from=${encodeURIComponent(from.toISOString())}&to=${encodeURIComponent(to.toISOString())}`).subscribe({next:x=>this.reportData.set(x),error:e=>alert(e.error?.message||'Não foi possível gerar o relatório.')})}
  reportBar(value:number,key:string){const rows=this.reportData()?.[key]||[];const max=Math.max(...rows.map((x:any)=>x.appointments??x.count),1);return Math.max(value/max*100,3)}
  exportReportCsv(){const r=this.reportData();if(!r)return;const lines=[['Relatório Ello Clinic'],[`Período`,this.reportFrom,this.reportTo],[],['Resumo'],['Atendimentos',r.summary.appointments],['Realizados',r.summary.completed],['Cancelados',r.summary.cancelled],['Faltas',r.summary.noShows],['Receita',r.summary.revenue],['Despesas',r.summary.expenses],[],['Profissional','Atendimentos','Realizados','Receita'],...r.byProfessional.map((x:any)=>[x.name,x.appointments,x.completed,x.revenue])];const csv=lines.map(row=>row.map((v:any)=>`"${String(v??'').replace(/"/g,'""')}"`).join(';')).join('\n');const blob=new Blob(['\ufeff'+csv],{type:'text/csv;charset=utf-8'});const url=URL.createObjectURL(blob);const a=document.createElement('a');a.href=url;a.download=`relatorio-ello-${this.reportFrom}-${this.reportTo}.csv`;a.click();URL.revokeObjectURL(url)}
  startOfWeek(date:Date){const d=new Date(date);const day=d.getDay();d.setDate(d.getDate()-(day===0?6:day-1));d.setHours(0,0,0,0);return d}
  weekDays(){return Array.from({length:7},(_,i)=>{const d=new Date(this.weekStart());d.setDate(d.getDate()+i);return d})}
  weekLabel(){const days=this.weekDays();return `${days[0].toLocaleDateString('pt-BR',{day:'2-digit',month:'short'})} — ${days[6].toLocaleDateString('pt-BR',{day:'2-digit',month:'short',year:'numeric'})}`}
  dayName(day:Date){return day.toLocaleDateString('pt-BR',{weekday:'short'}).replace('.','')}
  isToday(day:Date){const now=new Date();return day.toDateString()===now.toDateString()}
  changeWeek(amount:number){const d=new Date(this.weekStart());d.setDate(d.getDate()+amount*7);this.weekStart.set(d);this.loadAgenda()}
  goToday(){this.weekStart.set(this.startOfWeek(new Date()));this.loadAgenda()}
  filteredAppointments(){return this.appointments().filter(a=>(!this.agendaProfessional||a.professionalId===this.agendaProfessional)&&(!this.agendaStatus||a.status===this.agendaStatus))}
  appointmentsForDay(day:Date){const end=new Date(day);end.setDate(end.getDate()+1);return this.filteredAppointments().filter(a=>{const d=new Date(a.startsAt);return d>=day&&d<end})}
  todayAppointments(){const today=new Date();today.setHours(0,0,0,0);const end=new Date(today);end.setDate(end.getDate()+1);return this.appointments().filter(a=>new Date(a.startsAt)>=today&&new Date(a.startsAt)<end)}
  toLocalInput(value:Date|string){const d=new Date(value);const pad=(n:number)=>String(n).padStart(2,'0');return `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}T${pad(d.getHours())}:${pad(d.getMinutes())}`}
  editAppointment(row:any){this.openForm('appointment',{...row,startsAt:this.toLocalInput(row.startsAt),endsAt:this.toLocalInput(row.endsAt),roomId:row.roomId||''})}
  cancelAppointment(row:any){if(!confirm(`Deseja cancelar o atendimento de ${row.patient?.name}?`))return;this.http.delete(`${api}/appointments/${row.id}`).subscribe({next:()=>this.loadAgenda(),error:e=>alert(e.error?.message||'Não foi possível cancelar o atendimento.')})}
  shareAppointment(row:any){this.http.post<any>(`${api}/appointments/${row.id}/confirmation-link`,{}).subscribe({next:async r=>{const link=`${location.origin}${r.path}`;const text=this.confirmationMessage(row,link);try{if(navigator.share){await navigator.share({title:'Confirmação de consulta — Ello Clinic',text,url:link});this.toast.set('Compartilhamento aberto')}else{await navigator.clipboard.writeText(text);this.toast.set('Mensagem e link copiados')}}catch(error:any){if(error?.name!=='AbortError'){try{await navigator.clipboard.writeText(text);this.toast.set('Mensagem e link copiados')}catch{prompt('Copie a mensagem de confirmação:',text)}}}setTimeout(()=>this.toast.set(''),3500)},error:e=>alert(e.error?.message||'Não foi possível gerar o link de confirmação.')})}
  confirmationMessage(row:any,link:string){const start=new Date(row.startsAt);const date=start.toLocaleDateString('pt-BR');const time=start.toLocaleTimeString('pt-BR',{hour:'2-digit',minute:'2-digit'});return `Olá, ${this.firstName(row.patient?.name)}! Temos um atendimento agendado com ${row.professional?.name} no dia ${date}, às ${time}. Por favor, confirme sua presença, solicite remarcação ou cancelamento pelo link: ${link}`}
  loadPublic(){this.publicLoading.set(true);this.http.get<any>(`${api}/public/appointments/confirmation/${encodeURIComponent(this.publicToken)}`).subscribe({next:r=>{this.publicAppointment.set(r);this.publicLoading.set(false)},error:e=>{this.publicError.set(e.error?.message||'O link é inválido ou expirou.');this.publicLoading.set(false)}})}
  firstName(name:string){return (name||'').trim().split(' ')[0]}
  selectPublicAction(action:string){this.publicAction.set(action)}
  respondPublic(response:string){if(!this.publicForm.respondentName.trim()){this.publicError.set('Informe o nome de quem está respondendo.');setTimeout(()=>this.publicError.set(''),3000);return}this.publicLoading.set(true);this.http.post<any>(`${api}/public/appointments/confirmation/${encodeURIComponent(this.publicToken)}/respond`,{response,respondentName:this.publicForm.respondentName,message:this.publicForm.message}).subscribe({next:r=>{this.publicResult.set(r);this.publicLoading.set(false)},error:e=>{this.publicError.set(e.error?.message||'Não foi possível registrar sua resposta.');this.publicLoading.set(false)}})}
  publicResponseLabel(value:string){return ({Confirmed:'presença confirmada',CancellationRequested:'cancelamento solicitado',RescheduleRequested:'remarcação solicitada'} as any)[value]||value}
  closeForm(event:Event){event.stopPropagation();this.formOpen.set(false)}
}
bootstrapApplication(App,{providers:[provideHttpClient(withInterceptors([authInterceptor]))]}).catch(console.error);
